solution:
function doubleAll(nums) {
  // result holds the transformed values
  const result = [];
  // process every element in order
  for (let i = 0; i < nums.length; i++) {
    // multiply by 2 and store in the new array
    result.push(nums[i] * 2);
  }
  // return the mapped array
  return result;
}
